63	input         cdma_dat_done_status1;
64	input         cdma_wt_done_status0;
65	input         cdma_wt_done_status1;
66	input         cdp_done_status0;
67	input         cdp_done_status1;
68	input  [62:0] csb2glb_req_pd;
69	input         csb2glb_req_pvld;
70	input         pdp_done_status0;
71	input         pdp_done_status1;
72	input         rubik_done_status0;
73	input         rubik_done_status1;
74	input         sdp_done_status0;
