76	output        bdma_done_mask0;
77	output        bdma_done_mask1;
78	output        cacc_done_mask0;
79	output        cacc_done_mask1;
80	output        cdma_dat_done_mask0;
81	output        cdma_dat_done_mask1;
82	output        cdma_wt_done_mask0;
83	output        cdma_wt_done_mask1;
84	output        cdp_done_mask0;
85	output        cdp_done_mask1;
86	output        csb2glb_req_prdy;
87	output [33:0] glb2csb_resp_pd;
88	output        glb2csb_resp_valid;
89	output        pdp_done_mask0;
90	output        pdp_done_mask1;
91	output [31:0] req_wdat;
92	output        rubik_done_mask0;
93	output        rubik_done_mask1;
94	output        sdp_done_mask0;
95	output        sdp_done_mask1;
96	output        sdp_done_set0_trigger;
97	output        sdp_done_status0_trigger;
98	reg    [33:0] glb2csb_resp_pd;
99	reg           glb2csb_resp_valid;
100	reg    [62:0] req_pd;
101	reg           req_vld;
102	wire          bdma_done_set0;
103	wire          bdma_done_set1;
104	wire          cacc_done_set0;
105	wire          cacc_done_set1;
106	wire          cdma_dat_done_set0;
107	wire          cdma_dat_done_set1;
108	wire          cdma_wt_done_set0;
109	wire          cdma_wt_done_set1;
110	wire          cdp_done_set0;
111	wire          cdp_done_set1;
112	wire          pdp_done_set0;
113	wire          pdp_done_set1;
114	wire   [11:0] reg_offset;
115	wire   [31:0] reg_rd_data;
116	wire   [31:0] reg_wr_data;
117	wire          reg_wr_en;
118	wire   [21:0] req_addr;
119	wire    [1:0] req_level_NC;
120	wire          req_nposted;
121	wire          req_srcpriv_NC;
122	wire    [3:0] req_wrbe_NC;
123	wire          req_write;
124	wire   [33:0] rsp_pd;
125	wire          rsp_rd_error;
126	wire   [32:0] rsp_rd_pd;
127	wire   [31:0] rsp_rd_rdat;
128	wire          rsp_rd_vld;
129	wire          rsp_vld;
130	wire          rsp_wr_error;
131	wire   [32:0] rsp_wr_pd;
132	wire   [31:0] rsp_wr_rdat;
133	wire          rsp_wr_vld;
134	wire          rubik_done_set0;
135	wire          rubik_done_set1;
136	wire          sdp_done_set0;
137	wire          sdp_done_set1;
138	
139	
140	//////////////////////////////////////////////////////////
141	////  register
142	//////////////////////////////////////////////////////////
143	
144	//tie 0 for wo type register read
145	assign bdma_done_set0 = 1'b0;
146	assign bdma_done_set1 = 1'b0;
147	assign cdp_done_set0  = 1'b0;
148	assign cdp_done_set1  = 1'b0;
149	assign pdp_done_set0  = 1'b0;
150	assign pdp_done_set1  = 1'b0;
151	assign sdp_done_set0  = 1'b0;
152	assign sdp_done_set1  = 1'b0;
153	assign rubik_done_set0  = 1'b0;
154	assign rubik_done_set1  = 1'b0;
155	assign cdma_dat_done_set0  = 1'b0;
156	assign cdma_dat_done_set1  = 1'b0;
157	assign cdma_wt_done_set0  = 1'b0;
158	assign cdma_wt_done_set1  = 1'b0;
159	assign cacc_done_set0  = 1'b0;
160	assign cacc_done_set1  = 1'b0;
161	
162	// synoff nets
163	
164	// monitor nets
165	
166	// debug nets
167	
168	// tie high nets
169	
170	// tie low nets
171	
172	// no connect nets
173	
174	// not all bits used nets
175	
176	// todo nets
177	
178	    // &Viva width_learning_on;
179	// REQ INTERFACE
180	
181	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
182	  if (!nvdla_core_rstn) begin
183	    req_vld <= 1'b0;
184	  end else begin
185	  req_vld <= csb2glb_req_pvld;
186	  end
187	end
188	always @(posedge nvdla_core_clk) begin
189	  if ((csb2glb_req_pvld) == 1'b1) begin
190	    req_pd <= csb2glb_req_pd;
191	  // VCS coverage off
192	  end else if ((csb2glb_req_pvld) == 1'b0) begin
193	  end else begin
194	    req_pd <= 'bx;  // spyglass disable STARC-2.10.1.6 W443 NoWidthInBasedNum-ML -- (Constant containing x or z used, Based number `bx contains an X, Width specification missing for based number)
195	  // VCS coverage on
196	  end
197	end
198	assign csb2glb_req_prdy = 1'b1;
199	
200	// ========
201	// REQUEST
202	// ========
203	// flow=pvld_prdy 
204	assign req_level_NC = req_pd[62:61];
205	assign req_nposted = req_pd[55:55];
206	assign req_addr = req_pd[21:0];
207	assign req_wrbe_NC = req_pd[60:57];
208	assign req_srcpriv_NC = req_pd[56:56];
209	assign req_write = req_pd[54:54];
210	assign req_wdat = req_pd[53:22];
211	// ========
212	// RESPONSE
213	// ========
214	// flow=valid 
215	// packet=dla_xx2csb_rd_erpt 
216	assign rsp_rd_pd[32:32] = rsp_rd_error;
217	assign rsp_rd_pd[31:0] = rsp_rd_rdat;
218	// packet=dla_xx2csb_wr_erpt 
219	assign rsp_wr_pd[32:32] = rsp_wr_error;
220	assign rsp_wr_pd[31:0] = rsp_wr_rdat;
221	
222	
223	assign rsp_rd_vld  = req_vld & ~req_write;
224	assign rsp_rd_rdat = {32{rsp_rd_vld}} & reg_rd_data;
225	assign rsp_rd_error  = 1'b0;
226	
227	assign rsp_wr_vld  = req_vld & req_write & req_nposted;
228	assign rsp_wr_rdat = {32{1'b0}};
229	assign rsp_wr_error  = 1'b0;
230	
231	// ========
232	// REQUEST
233	// ========
234	assign rsp_vld = rsp_rd_vld | rsp_wr_vld;
235	assign rsp_pd[33:33] = ({1{rsp_rd_vld}} & {1'h0}) 
236	                                | ({1{rsp_wr_vld}} & {1'h1});
237	
238	assign rsp_pd[32:0] = ({33{rsp_rd_vld}} & rsp_rd_pd)
239	                                | ({33{rsp_wr_vld}} & rsp_wr_pd);
240	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
241	  if (!nvdla_core_rstn) begin
242	    glb2csb_resp_valid <= 1'b0;
243	  end else begin
244	  glb2csb_resp_valid <= rsp_vld;
245	  end
246	end
247	always @(posedge nvdla_core_clk) begin
248	  if ((rsp_vld) == 1'b1) begin
249	    glb2csb_resp_pd <= rsp_pd;
250	  // VCS coverage off
